        {
            if (_cache.TryGetValue(filePath, out bitmap) && _peakCache.TryGetValue(filePath, out peaks))
                return true;
            bitmap = null;
            peaks = null;
            return false;
        }

        public void Clear() { _cache.Clear(); _peakCache.Clear(); }
