private void BottomResize_MouseDown(object sender, MouseButtonEventArgs e) { StartWindowResize(sender, e, "bottom"); }

private void StartWindowResize(object sender, MouseButtonEventArgs e, string direction)
{
    _isWindowResizing = true;
    _windowResizeStartX = e.GetPosition(this).X;
    _windowResizeStartY = e.GetPosition(this).Y;
    _windowResizeStartWidth = Width;
    _windowResizeStartHeight = Height;
    _windowResizeDirection = direction;
    Mouse.Capture((UIElement)sender);
    e.Handled = true;
}

private void TopResize_MouseMove(object sender, MouseEventArgs e) { DoWindowResize(e); }
private void BottomResize_MouseMove(object sender, MouseEventArgs e) { DoWindowResize(e); }

private void DoWindowResize(MouseEventArgs e)
{
    if (!_isWindowResizing) return;
    var pos = e.GetPosition(this);
    var dy = pos.Y - _windowResizeStartY;

    switch (_windowResizeDirection)
    {
        case "top":
            var newH = _windowResizeStartHeight - dy;
            if (newH >= MinHeight) { Height = newH; Top += dy; }
            break;
        case "bottom":
            Height = Math.Max(MinHeight, _windowResizeStartHeight + dy);
            break;
    }
}

private void Resize_MouseUp(object sender, MouseButtonEventArgs e)
{
    _isWindowResizing = false;
    Mouse.Capture(null);
}

